sql:
SELECT AVG(fe.combined_mpg) AS overall_avg_combined_mpg
FROM fuel_efficiency fe
JOIN vehicles v ON fe.vehicle_id = v.vehicle_id;

SELECT DISTINCT make
FROM vehicles
ORDER BY make;

external_knowledge:
fuel-efficient refers to vehicles with high combined MPG; 
the ranking is based on the combined MPG within each class, where 'combined MPG' represents the average MPG for a vehicle in city and highway driving conditions;
the number of accesses refers to how many times a vehicle has been accessed or viewed.

sql:
SELECT AVG(combined_mpg) AS avg_combined_mpg, COUNT(*) AS num_vehicles_tested
FROM fuel_efficiency
WHERE test_location = 'Detroit';
